#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline ll read(){
    ll x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(int x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MAXN=1e6+5;
ll t,n,id,a[MAXN];
int main(void){
	t=read(),id=read();
	while(t--)
    {
		n=read();
		bool bo=1;
		for(int i=1;i<=n;++i)a[i]=read();
		if(n<4)puts("No");
		else{
		    sort(a+1,a+n+1);
		    int l=2,r=n-1;
		    while(true)
            {
		    	if(l==r)
                {
		    		puts("No");
                    break;
		    	}
		    	else if((a[l]-a[1])==(a[n]-a[r]))
                {
	       			puts("Yes");
                    break;
		    	}
		    	else if((a[l]-a[1])<(a[n]-a[r]))
                {
                   ++l;
                }
		    	else --r;
		    }
		}
	}
	return false;
}
